+using System.Diagnostics;
+using Microsoft.AspNetCore.Components;
+using Microsoft.AspNetCore.Components.Authorization;
+using Microsoft.AspNetCore.Components.Web;
+using sv_83268f4f22ac4bb6b6e226f3ce7b3575.Client;
+using System.Security.Claims;
+
+namespace sv_83268f4f22ac4bb6b6e226f3ce7b3575;
+
+/// <summary>
+/// Subscribes to <see cref="AuthenticationStateProvider.AuthenticationStateChanged"/> and
+/// persists the current user info into <see cref="PersistentComponentState"/> so the
+/// client-side <see cref="PersistentAuthenticationStateProvider"/> can pick it up
+/// after the WebAssembly runtime activates.
+/// </summary>
+public sealed class PersistingServerAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
+{
+    private readonly PersistentComponentState _persistentComponentState;
+    private readonly AuthenticationStateProvider _authenticationStateProvider;
+    private readonly PersistingComponentStateSubscription _subscription;
+    private Task<AuthenticationState>? _authenticationStateTask;
+
+    public PersistingServerAuthenticationStateProvider(
+        PersistentComponentState persistentComponentState,
+        AuthenticationStateProvider authenticationStateProvider)
+    {
+        _persistentComponentState = persistentComponentState;
+        _authenticationStateProvider = authenticationStateProvider;
+
+        authenticationStateProvider.AuthenticationStateChanged += OnAuthenticationStateChanged;
+        _subscription = persistentComponentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
+    }
+
+    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
+    {
+        _authenticationStateTask = authenticationStateTask;
+    }
+
+    private void OnAuthenticationStateChanged(Task<AuthenticationState> authenticationStateTask)
+    {
+        _authenticationStateTask = authenticationStateTask;
+    }
+
+    private async Task OnPersistingAsync()
+    {
+        var authState = await (_authenticationStateTask ?? _authenticationStateProvider.GetAuthenticationStateAsync());
+        var principal = authState.User;
+
+        if (principal.Identity?.IsAuthenticated == true)
+        {
+            var email = principal.FindFirst(ClaimTypes.Email)?.Value
+                        ?? principal.FindFirst(ClaimTypes.Name)?.Value;
+            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();
+
+            if (email is not null)
+            {
+                _persistentComponentState.PersistAsJson(nameof(UserInfo), new UserInfo
+                {
+                    Email = email,
+                    Roles = roles,
+                });
+            }
+        }
+    }
+
+    public void Dispose()
+    {
+        _subscription.Dispose();
+        _authenticationStateProvider.AuthenticationStateChanged -= OnAuthenticationStateChanged;
+    }
+}
